--- 战斗对象移动表演器
---@class LFightMoveActor
local LFightMoveActor = LxClass("LFightMoveActor",nil)
----------------------------------------------------------------
-----------------------------------------------------------------
function LFightMoveActor:LFightMoveActor(battleUnit,obj)
	---@type LFightUnit
	self._battleUnit = battleUnit
	---@type LFightObject
	self._obj = obj

	self._endTime = 0
	self._isMoving = false
end


function LFightMoveActor:OnRun(time)
	if not self._isMoving then return end
	if self._endTime < time then
		self._obj:SetPosition(self._targetPos)
		self:StopMove()
	end
end

function LFightMoveActor:MoveTo(pos,time,endCall)
	self._targetPos = pos
	local btObjectView = self._obj:GetBtObjectView()
	if not btObjectView then
		return 
	end
	btObjectView:StartMove(pos,time)
	self._isMoving = true
	self._isJumping = false
	self._endTime = self._battleUnit:GetTime() + time
	self._endCall = endCall
end

function LFightMoveActor:JumpTo(pos,topPos,time)
	self._targetPos = pos
	local btObjectView = self._obj:GetBtObjectView()
	btObjectView:StartJump(pos, topPos, time, 0)
	self._isMoving = true
	self._isJumping = true
	self._endTime = self._battleUnit:GetTime() + time
end

function LFightMoveActor:StopMove()
	if(not self._isMoving) then return end
	self._isMoving = false
	self._isJumping = false
	local btObjectView = self._obj:GetBtObjectView()
	btObjectView:StopMove()

	local endCall = self._endCall
	self._endCall = nil
	if endCall then
		endCall()
	end
end

function LFightMoveActor:IsMoving()
	return self._isMoving
end

function LFightMoveActor:Destroy()
	self._obj = nil
	self._battleUnit = nil
end

function LFightMoveActor:GetTargetPos()
	return self._targetPos
end

return LFightMoveActor